import { getServerSession } from 'next-auth';
import { google } from 'googleapis';
import Anthropic from '@anthropic-ai/sdk';
import { Readable } from 'stream';
import { authOptions } from '../../auth/[...nextauth]/route';
import {
  Document, Header, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, Packer, WidthType, BorderStyle, ShadingType, TableLayoutType,
  HorizontalPositionRelativeFrom, VerticalPositionRelativeFrom,
  TextWrappingType, PageOrientation, ExternalHyperlink,
} from 'docx';

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

async function scrapeUrl(url) {
  if (!url) return '';
  try {
    const res = await fetch(`https://r.jina.ai/${url}`, {
      headers: { 'Accept': 'text/plain', 'X-Timeout': '10' },
      signal: AbortSignal.timeout(12000),
    });
    if (!res.ok) return '';
    const text = await res.text();
    return text.slice(0, 15000);
  } catch {
    return '';
  }
}

async function scrapeWebsite(url) {
  if (!url) return '';
  try {
    const base = new URL(url).origin;
    const aboutPaths = ['/about', '/about-us', '/company', '/who-we-are', '/our-story'];
    const pages = await Promise.all([
      scrapeUrl(url),
      ...aboutPaths.map(p => scrapeUrl(base + p)),
    ]);
    const combined = pages.filter(Boolean).join('\n\n---\n\n');
    return combined.slice(0, 20000);
  } catch {
    return scrapeUrl(url);
  }
}

async function searchJina(query) {
  try {
    const encoded = encodeURIComponent(query);
    const res = await fetch(`https://s.jina.ai/${encoded}`, {
      headers: { 'Accept': 'text/plain', 'X-Timeout': '10' },
      signal: AbortSignal.timeout(12000),
    });
    if (!res.ok) return '';
    const text = await res.text();
    return text.slice(0, 8000);
  } catch {
    return '';
  }
}

const LOGO_B64 = '';

function buildPrompt({ companyName, website, linkedin, additionalNote, websiteContent, linkedinContent, crunchbaseContent, fundingContent }) {
  return `Company Name: ${companyName}
Website: ${website || 'Not provided'}
LinkedIn: ${linkedin || 'Not provided'}
Additional Note: ${additionalNote || 'None'}

Client Intake Instructions:
1. Official Name: Provide the full legal name of the company along with its primary city and country of operation.
2. Registration Number: Provide the full registration number of the company.
3. Industry: Specify the industry or sector the company operates in (e.g., Technology, Healthcare, Finance).
4. Company Size (Number of Employees): Indicate the total number of employees.
5. Current Funding: Detail the current funding status, including recent funding rounds, amounts raised, and key investors if applicable.
6. Office Location(s): List all office locations, including headquarters and any regional offices.
7. Elevator Pitch: Craft a concise and compelling summary of the company's value proposition.
8. Mission/Vision: Outline the company's mission statement and long-term vision.
9. Company Background: Provide a brief history of the company, including founding date, key milestones, and significant achievements.
10. Services/Products: Describe the main services or products offered by the company.
11. Unique Selling Points (USP): Highlight what sets the company apart from its competitors.
12. Target Market: Define the primary audience or customer segments the company serves.
13. Main Competitors: Identify key competitors in the industry.
14. Company Culture: Describe the work environment, values, and cultural aspects that define the company.
15. Qualities Valued Most in Employees: List the key attributes and skills the company seeks in its employees.
16. Website: Provide the official website URL.

${websiteContent ? `--- Website Content (${website}) ---
${websiteContent}
` : ''}${linkedinContent ? `--- LinkedIn Content (${linkedin}) ---
${linkedinContent}
` : ''}${crunchbaseContent ? `--- Crunchbase Search Results ---
${crunchbaseContent}
` : ''}${fundingContent ? `--- Funding & Investors Search Results ---
${fundingContent}
` : ''}
Return ONLY a valid JSON object with exactly these keys. No markdown, no explanation, just the JSON:

{
  "registeredName": "",
  "registrationNumber": "",
  "industry": "",
  "companySize": "",
  "currentFunding": "",
  "officeLocations": "",
  "elevatorPitch": "",
  "mission": "",
  "vision": "",
  "companyBackground": "",
  "servicesProducts": [],
  "usp": [],
  "targetMarket": [],
  "mainCompetitors": "",
  "companyCulture": "",
  "qualitiesValued": ""
}`;
}

async function buildDocx({ companyName, website, linkedin, date, data }) {
  const logoBuffer = Buffer.from(LOGO_B64, 'base64');

  const txt = (text, opts = {}) => new TextRun({
    text: String(text ?? ''),
    font: 'Poppins',
    size: 20,
    ...opts,
  });

  const CB = { style: BorderStyle.SINGLE, size: 4, color: '000000' };
  const cellBorders = { top: CB, bottom: CB, left: CB, right: CB };
  const shade = (fill) => ({ fill, type: ShadingType.CLEAR, color: 'auto' });

  const divider = () => new Paragraph({
    children: [],
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: 'A0A0A0', space: 1 } },
    spacing: { before: 0, after: 200, line: 240, lineRule: 'auto' },
  });

  const sectionHead = (text) => new Paragraph({
    children: [txt(text, { bold: true, color: '424495' })],
    spacing: { before: 0, after: 0, line: 240, lineRule: 'auto' },
  });

  const cellPad = { top: 100, bottom: 100, left: 100, right: 100 };
  const sp = (after = 200) => ({ before: 0, after, line: 240, lineRule: 'auto' });

  const lCell = (content) => {
    const children = Array.isArray(content)
      ? content
      : [new Paragraph({ children: [txt(String(content || ''))], spacing: sp() })];
    return new TableCell({ width: { size: 3165, type: WidthType.DXA }, borders: cellBorders, shading: shade('F7F7F7'), margins: cellPad, children });
  };

  const vCell = (content, fill = 'FFFFFF') => {
    const children = Array.isArray(content)
      ? content
      : [new Paragraph({ children: [txt(String(content || ''))], spacing: sp() })];
    return new TableCell({ borders: cellBorders, ...(fill ? { shading: shade(fill) } : {}), margins: cellPad, children });
  };

  const simpleRow = (label, value, valueFill = 'FFFFFF') =>
    new TableRow({ children: [lCell(label), vCell(String(value || '—'), valueFill)] });

  const toBullets = (val, lastAfter = 80) => {
    const items = Array.isArray(val) ? val : String(val || '').split('\n').filter(Boolean);
    if (!items.length) return [new Paragraph({ children: [txt('—')], spacing: sp() })];
    return items.map((item, i) => new Paragraph({
      children: [txt('●  ' + item)],
      indent: { left: 720, hanging: 360 },
      spacing: sp(i === items.length - 1 ? lastAfter : 0),
    }));
  };

  const table1 = new Table({
    width: { size: 9135, type: WidthType.DXA },
    columnWidths: [3165, 5970],
    layout: TableLayoutType.FIXED,
    rows: [
      simpleRow('Registered Name', data.registeredName),
      simpleRow('Registration Number', data.registrationNumber),
      simpleRow('Job Industry', data.industry),
      new TableRow({
        children: [
          new TableCell({
            width: { size: 3165, type: WidthType.DXA },
            borders: cellBorders,
            shading: shade('F7F7F7'),
            margins: cellPad,
            children: [
              new Paragraph({ children: [txt('Company Size ')], spacing: sp(200) }),
              new Paragraph({ children: [txt('(number of employees)')], spacing: sp(200) }),
            ],
          }),
          vCell(String(data.companySize || '—')),
        ],
      }),
      simpleRow('Current Funding', data.currentFunding),
      simpleRow('Office Location(s)', data.officeLocations, null),
    ],
  });

  const table2 = new Table({
    width: { size: 9165, type: WidthType.DXA },
    columnWidths: [3135, 6030],
    layout: TableLayoutType.FIXED,
    rows: [
      new TableRow({
        height: { value: 695, rule: 'atLeast' },
        children: [lCell('Elevator Pitch'), vCell(String(data.elevatorPitch || '—'))],
      }),
      new TableRow({
        height: { value: 695, rule: 'atLeast' },
        children: [
          lCell('Mission / Vision'),
          vCell([
            new Paragraph({ children: [txt('Mission:  ', { bold: true }), txt(data.mission || '—')], spacing: sp() }),
            new Paragraph({ children: [txt('Vision:  ', { bold: true }), txt(data.vision || '—')], spacing: sp() }),
          ]),
        ],
      }),
      simpleRow('Company Background', data.companyBackground),
      new TableRow({ children: [lCell('Services / Products'), vCell(toBullets(data.servicesProducts))] }),
      new TableRow({ children: [lCell('Unique Selling Points (USP)'), vCell(toBullets(data.usp))] }),
      new TableRow({ children: [lCell('Target Market'), vCell(toBullets(data.targetMarket, 200))] }),
      new TableRow({
        children: [
          lCell('Main Competitors'),
          vCell(toBullets(
            Array.isArray(data.mainCompetitors)
              ? data.mainCompetitors
              : (data.mainCompetitors || '').split(',').map(s => s.trim()).filter(Boolean),
            80
          ), null),
        ],
      }),
    ],
  });

  const table3 = new Table({
    width: { size: 9135, type: WidthType.DXA },
    columnWidths: [3120, 6015],
    layout: TableLayoutType.FIXED,
    rows: [
      simpleRow('Company Culture', data.companyCulture),
      simpleRow('Qualities Valued in Employees', data.qualitiesValued),
    ],
  });

  const linkCell = (url) => {
    const resolved = url && url !== '—' ? url : null;
    const children = resolved
      ? [new Paragraph({
          children: [new ExternalHyperlink({
            link: resolved,
            children: [txt(resolved, { color: '1155CC', underline: {} })],
          })],
          spacing: sp(),
        })]
      : [new Paragraph({ children: [txt('—')], spacing: sp() })];
    return new TableCell({ borders: cellBorders, shading: shade('FFFFFF'), margins: cellPad, children });
  };

  const table4 = new Table({
    width: { size: 9195, type: WidthType.DXA },
    columnWidths: [3165, 6030],
    layout: TableLayoutType.FIXED,
    rows: [
      new TableRow({ children: [lCell('Website'), linkCell(website || data.website)] }),
      new TableRow({ children: [lCell('LinkedIn'), linkCell(linkedin)] }),
    ],
  });

  const spacer = () => new Paragraph({ children: [], spacing: sp() });

  const doc = new Document({
    sections: [{
      properties: {
        page: {
          size: { width: 11906, height: 16838, orientation: PageOrientation.PORTRAIT },
          margin: { top: 1080, bottom: 1080, left: 1080, right: 1110, header: 288, footer: 720 },
        },
      },
      headers: {
        default: new Header({
          children: [new Paragraph({
            children: [new ImageRun({
              type: 'png',
              data: logoBuffer,
              transformation: { width: 148, height: 24 },
              floating: {
                horizontalPosition: { relative: HorizontalPositionRelativeFrom.PAGE, offset: 5769864 },
                verticalPosition: { relative: VerticalPositionRelativeFrom.PAGE, offset: 219456 },
                wrap: { type: TextWrappingType.NONE },
                behindDocument: false,
              },
            })],
          })],
        }),
      },
      children: [
        new Paragraph({
          children: [txt(`Company Name: ${companyName}`, { bold: true, size: 30, color: '424495' })],
          spacing: sp(),
        }),
        divider(),
        new Paragraph({ children: [txt(`Intake by:  ${data.intakeBy || 'StartupBreed'}`)], spacing: sp() }),
        new Paragraph({ children: [txt(`Date:  ${date}`)], spacing: sp() }),
        divider(),
        sectionHead('General Information'),
        divider(),
        table1,
        spacer(),
        sectionHead('Company Information'),
        divider(),
        table2,
        spacer(),
        sectionHead('Company Culture & Values'),
        divider(),
        table3,
        spacer(),
        sectionHead('Resources'),
        divider(),
        table4,
        spacer(),
      ],
    }],
  });

  return Packer.toBuffer(doc);
}

export async function POST(request) {
  const session = await getServerSession(authOptions);
  if (!session) return Response.json({ error: 'Unauthorized' }, { status: 401 });

  const body = await request.json();
  const { companyName, website, linkedin, additionalNote, folderId } = body;
  if (!companyName || !folderId) return Response.json({ error: 'Missing required fields' }, { status: 400 });

  const [websiteContent, linkedinContent, crunchbaseContent, fundingContent] = await Promise.all([
    scrapeWebsite(website),
    scrapeUrl(linkedin),
    searchJina(`${companyName} crunchbase`),
    searchJina(`${companyName} funding investors`),
  ]);

  let data;
  try {
    const message = await anthropic.messages.create({
      model: 'claude-sonnet-4-6',
      max_tokens: 16000,
      system: 'You are a professional recruitment consultant. Return only valid JSON, no markdown, no explanation.',
      messages: [{ role: 'user', content: buildPrompt({ ...body, websiteContent, linkedinContent, crunchbaseContent, fundingContent }) }],
    });
    const text = message.content[0].text.trim();
    const jsonStart = text.indexOf('{');
    const jsonEnd = text.lastIndexOf('}');
    data = JSON.parse(text.slice(jsonStart, jsonEnd + 1));
  } catch (err) {
    return Response.json({ error: 'Generation failed: ' + err.message }, { status: 500 });
  }

  const date = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
  const docxBuffer = await buildDocx({ companyName, website, linkedin, date, data });

  const auth = new google.auth.OAuth2();
  auth.setCredentials({ access_token: session.access_token });
  const drive = google.drive({ version: 'v3', auth });

  try {
    const res = await drive.files.create({
      requestBody: {
        name: `Client Intake_ ${companyName}`,
        parents: [folderId],
        mimeType: 'application/vnd.google-apps.document',
      },
      media: {
        mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        body: Readable.from(docxBuffer),
      },
      fields: 'id, name',
    });
    return Response.json({ success: true, file: res.data });
  } catch (err) {
    return Response.json({ error: 'Drive save failed: ' + err.message }, { status: 500 });
  }
}
